                    (config.command === 'build' && pluginOptions.injectOnBuild);
                if (!shouldInject || !injectionBundle) {
                    return html;
                }
                if (pluginOptions.verbose) {
                    console.log('💉 IWSDK Dev: Injecting runtime script into HTML');
                }
